};

if (params.tipo_agendamiento && params.tipo_agendamiento !== 'null') data.tipo = params.tipo_agendamiento;
if (params.fecha_hora && params.fecha_hora !== 'null') data.fecha_hora = params.fecha_hora;
if (params.horario_preferido && params.horario_preferido !== 'null') data.horario_preferido = params.horario_preferido;
if (params.numero_habitaciones && params.numero_habitaciones !== 'null') data.habitaciones = params.numero_habitaciones;
if (params.intencion_compra && params.intencion_compra !== 'null') data.intencion = params.intencion_compra;
if (params.metodo_contacto_pref && params.metodo_contacto_pref !== 'null') data.contacto_pref = params.metodo_contacto_pref;
